export const protocol_https = "# Customer-support replies sent from the agent are scanned by an LLM\n# judge before they go out: catches offensive content, missing\n# salutations, and markdown that shouldn't ship.\nrule \"support-reply-on-behalf\" {\n  endpoint = deno-deploy\n  condition = <<-CEL\n    http.method == 'POST'\n    && http.path == '/api/admin.supportTickets.replyOnBehalf'\n  CEL\n  approve = [reply-content-judge]\n}\n\n# ===== harness =====\n\nadmin_email = \"ops@example.com\"\n\npolicy \"reply-content\" {\n  text = <<-EOT\n    The JSON body has a body field containing a customer support\n    reply. Deny if it contains markdown formatting, missing\n    salutations, or offensive content.\n  EOT\n}\n\ncredential \"anthropic_manual_key\" \"anthropic-key\" {}\ncredential \"bearer_token\" \"deno-deploy-cred\" {}\n\napprover \"llm_approver\" \"reply-content-judge\" {\n  model      = \"claude-sonnet-4-6\"\n  credential = anthropic-key\n  policy     = reply-content\n}\n\nendpoint \"https\" \"deno-deploy\" {\n  hosts      = [\"app.deno.com\"]\n  credential = deno-deploy-cred\n}\n\nprofile \"default\" { endpoints = [deno-deploy] }\n";
export const protocol_k8s = "# kubectl exec is gated by an LLM judge that reads the command argv:\n# allows ls / ps / df, denies env dumps, sensitive file reads, and\n# anything touching pod tokens or container sockets.\nrule \"k8s-exec-content-check\" {\n  endpoints = [k8s-dev, k8s-prod]\n  priority  = 500\n  condition = \"k8s.resource == 'pods/exec'\"\n  approve   = [k8s-exec-content-judge]\n}\n\n# ===== harness =====\n\nadmin_email = \"ops@example.com\"\n\npolicy \"k8s-exec-content\" {\n  text = <<-EOT\n    Inspect the kubectl exec command (each ?command= argv element).\n    Deny if it dumps env vars (env, printenv, set, export, cat\n    /proc/*/environ). Deny if it reads sensitive host-mount files.\n    Allow ls, ps, df, ip, ss, mount, dmesg, top.\n  EOT\n}\n\ncredential \"mtls_credential\" \"k8s-cred\" {}\ncredential \"anthropic_manual_key\" \"anthropic-key\" {}\n\napprover \"llm_approver\" \"k8s-exec-content-judge\" {\n  model      = \"claude-haiku-4-5-20251001\"\n  credential = anthropic-key\n  policy     = k8s-exec-content\n}\n\nendpoint \"kubernetes\" \"k8s-dev\" {\n  server     = \"k8s-dev.example\"\n  credential = k8s-cred\n}\n\nendpoint \"kubernetes\" \"k8s-prod\" {\n  server     = \"k8s-prod.example\"\n  credential = k8s-cred\n}\n\nprofile \"default\" { endpoints = [k8s-dev, k8s-prod] }\n";
export const protocol_sql = "# Block Postgres functions that could read the filesystem or open\n# outbound connections from inside the database — pg_read_file,\n# lo_get, and the whole dblink family.\nrule \"pg-banned-functions\" {\n  endpoint = pg-staging\n  priority = 100\n  condition = <<-CEL\n    sets.intersects(sql.functions, [\n      'pg_read_file', 'pg_read_binary_file', 'lo_get',\n    ])\n    || sql.functions.exists(f, f.startsWith('dblink_'))\n  CEL\n  verdict = \"deny\"\n  reason  = \"filesystem-reaching function\"\n}\n\n# ===== harness =====\n\nadmin_email = \"ops@example.com\"\n\ncredential \"postgres_credential\" \"pg-cred\" { user = \"agent\" }\n\nendpoint \"postgres\" \"pg-staging\" {\n  host       = \"pg-staging.example:5432\"\n  credential = pg-cred\n}\n\nprofile \"default\" { endpoints = [pg-staging] }\n";
export const rules_block = "# Block destructive SQL on prod\nrule \"no-prod-drops\" {\n  endpoint  = pg-prod\n  condition = \"sql.verb in ['drop', 'truncate', 'alter']\"\n  verdict   = \"deny\"\n}\n\n# Slack-approve any GitHub write\nrule \"github-writes\" {\n  endpoint  = github-api\n  condition = \"http.method in ['POST', 'PUT', 'DELETE']\"\n  approve   = [ops]\n}\n\n# ===== harness =====\n\nadmin_email = \"ops@example.com\"\n\ncredential \"postgres_credential\" \"pg-cred\"    { user = \"agent\" }\ncredential \"bearer_token\"        \"github-pat\" {}\ncredential \"slack_tokens\"        \"slack-bot\"  {}\n\nendpoint \"postgres\" \"pg-prod\" {\n  host       = \"pg-prod.example:5432\"\n  credential = pg-cred\n}\n\nendpoint \"https\" \"github-api\" {\n  hosts      = [\"api.github.com\"]\n  credential = github-pat\n}\n\napprover \"human_approver\" \"ops\" {\n  channel    = \"#agent-ops\"\n  credential = slack-bot\n}\n\nprofile \"default\" { endpoints = [pg-prod, github-api] }\n";
